import{bQ as a,aL as i,u as t,G as e}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"07｜执行计划与慢查询","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/07-执行计划与慢查询.md","filePath":"04.MySQL/07-执行计划与慢查询.md","lastUpdated":null}'),n={name:"04.MySQL/07-执行计划与慢查询.md"};function p(l,s,d,h,k,o){return i(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="_07-执行计划与慢查询" tabindex="-1">07｜执行计划与慢查询 <a class="header-anchor" href="#_07-执行计划与慢查询" aria-label="Permalink to &quot;07｜执行计划与慢查询&quot;">​</a></h1><p>上一篇讲了索引原理。但一条查询到底走了没走索引、扫了多少行、有没有额外排序，光靠猜不准。</p><p>本篇讲两个工具：EXPLAIN 让 MySQL 说出这条查询的执行计划，慢查询日志帮你找出哪些查询慢。这两个是排查慢查询的核心。</p><h2 id="一、为什么查询慢" tabindex="-1">一、为什么查询慢 <a class="header-anchor" href="#一、为什么查询慢" aria-label="Permalink to &quot;一、为什么查询慢&quot;">​</a></h2><p>一条查询慢，可能的原因：</p><ul><li>没走索引，全表扫描几百万行</li><li>走了索引但回表太多</li><li>用了 <code>filesort</code>（额外排序）或 <code>temporary</code>（临时表）</li><li>扫的行数远大于实际返回的行数</li></ul><p>要确认是哪种，用 EXPLAIN 看 MySQL 实际怎么执行这条查询。</p><h2 id="二、explain-看执行计划" tabindex="-1">二、EXPLAIN 看执行计划 <a class="header-anchor" href="#二、explain-看执行计划" aria-label="Permalink to &quot;二、EXPLAIN 看执行计划&quot;">​</a></h2><p>在查询前面加 <code>EXPLAIN</code>：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, uri, created_at</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user_id </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1001</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-05-01&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;2026-06-01&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>返回一行（或多行）结果，关键看几个字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>含义</th><th>关注点</th></tr></thead><tbody><tr><td><code>type</code></td><td>访问类型</td><td>const &gt; ref &gt; range &gt; index &gt; ALL，ALL 是全表扫</td></tr><tr><td><code>possible_keys</code></td><td>优化器能用的索引</td><td>为空说明没可用索引</td></tr><tr><td><code>key</code></td><td>实际选用的索引</td><td>NULL = 没走索引，全表扫</td></tr><tr><td><code>key_len</code></td><td>索引使用长度</td><td>看联合索引用了几列</td></tr><tr><td><code>rows</code></td><td>预估扫描行数</td><td>大但实际只返回几行时要关注</td></tr><tr><td><code>Extra</code></td><td>额外信息</td><td>看有没有 <code>filesort</code>、<code>temporary</code>、<code>Using index</code></td></tr></tbody></table><h3 id="type-访问类型好不好" tabindex="-1">type：访问类型好不好 <a class="header-anchor" href="#type-访问类型好不好" aria-label="Permalink to &quot;type：访问类型好不好&quot;">​</a></h3><p><code>type</code> 列从好到差：</p><table tabindex="0"><thead><tr><th>type</th><th>含义</th></tr></thead><tbody><tr><td><code>const</code></td><td>主键或唯一索引等值查询，最快</td></tr><tr><td><code>ref</code></td><td>非唯一索引等值查询</td></tr><tr><td><code>range</code></td><td>索引范围查询（&gt;、&lt;、BETWEEN、IN）</td></tr><tr><td><code>index</code></td><td>扫整棵索引树（比扫全表好，但也不理想）</td></tr><tr><td><code>ALL</code></td><td>全表扫描，最差</td></tr></tbody></table><p>看到 <code>ALL</code> 基本就是没走索引或索引失效了，要查原因。</p><h3 id="key-实际走了哪个索引" tabindex="-1">key：实际走了哪个索引 <a class="header-anchor" href="#key-实际走了哪个索引" aria-label="Permalink to &quot;key：实际走了哪个索引&quot;">​</a></h3><p><code>possible_keys</code> 列出可用的索引，<code>key</code> 是优化器实际选的。有时有索引但优化器没选（统计信息过期、查询条件让索引不划算），这时要分析为什么。</p><p><code>key</code> 是 <code>NULL</code> 表示全表扫——要么没建索引，要么索引失效了（参考上一篇的失效场景）。</p><h3 id="rows-扫了多少行" tabindex="-1">rows：扫了多少行 <a class="header-anchor" href="#rows-扫了多少行" aria-label="Permalink to &quot;rows：扫了多少行&quot;">​</a></h3><p><code>rows</code> 是优化器预估要扫描的行数。一条查询只返回 20 行，但 <code>rows</code> 显示 100 万——说明扫了 100 万行才筛出 20 行，效率很低。理想情况 <code>rows</code> 接近实际返回行数。</p><h3 id="extra-额外做了什么" tabindex="-1">Extra：额外做了什么 <a class="header-anchor" href="#extra-额外做了什么" aria-label="Permalink to &quot;Extra：额外做了什么&quot;">​</a></h3><p><code>Extra</code> 列透露额外操作：</p><table tabindex="0"><thead><tr><th>Extra</th><th>含义</th><th>好不好</th></tr></thead><tbody><tr><td><code>Using index</code></td><td>覆盖索引，不用回表</td><td>好</td></tr><tr><td><code>Using where</code></td><td>用 WHERE 过滤</td><td>正常</td></tr><tr><td><code>Using filesort</code></td><td>额外排序</td><td>差，要优化</td></tr><tr><td><code>Using temporary</code></td><td>用了临时表</td><td>差，要优化</td></tr></tbody></table><p><code>Using filesort</code> 意味着 MySQL 没法用索引的顺序直接返回结果，得额外排一次序。数据量大时排序很耗资源。<code>Using temporary</code> 更糟——要建临时表，通常出现在 GROUP BY、DISTINCT、ORDER BY 不同列时。</p><p>看到这两个要想办法优化——让排序能吃到索引顺序，或调整查询。</p><h2 id="三、一条慢查询的排查过程" tabindex="-1">三、一条慢查询的排查过程 <a class="header-anchor" href="#三、一条慢查询的排查过程" aria-label="Permalink to &quot;三、一条慢查询的排查过程&quot;">​</a></h2><p>实际走一遍。某接口反馈慢，对应查询：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;api&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> status_code </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 500</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>先 EXPLAIN：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">EXPLAIN </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> app_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;api&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> status_code </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 500</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> created_at </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>看输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>type: ALL              -- 全表扫</span></span>
<span class="line"><span>key: NULL              -- 没走索引</span></span>
<span class="line"><span>rows: 1000000          -- 扫 100 万行</span></span>
<span class="line"><span>Extra: Using filesort   -- 还额外排序</span></span></code></pre></div><p>三个问题：没走索引、扫全表、额外排序。建联合索引解决：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> access_logs </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ADD</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> KEY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> idx_app_status_time (app_name, status_code, created_at);</span></span></code></pre></div><p>（app_name 和 status_code 等值放前面，created_at 范围/排序放后面——上一篇讲的顺序原则）</p><p>再 EXPLAIN：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>type: ref              -- 走了索引</span></span>
<span class="line"><span>key: idx_app_status_time</span></span>
<span class="line"><span>rows: 50                -- 只扫 50 行</span></span>
<span class="line"><span>Extra: Using index      -- 不用回表</span></span></code></pre></div><p>从扫 100 万行变成扫 50 行，毫秒级返回。这就是索引优化的效果。</p><h2 id="四、慢查询日志" tabindex="-1">四、慢查询日志 <a class="header-anchor" href="#四、慢查询日志" aria-label="Permalink to &quot;四、慢查询日志&quot;">​</a></h2><p>线上不可能每条查询都手动 EXPLAIN。开慢查询日志，让 MySQL 自动记录超过阈值的查询：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># my.cnf</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">slow_query_log</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">slow_query_log_file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = /data/mysql/logs/slow.log</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">long_query_time</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1      -- 超过 1 秒的记录</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">log_queries_not_using_indexes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> = 1   -- 没走索引的也记录</span></span></code></pre></div><p>改完重启生效。之后所有超过 1 秒的查询会被记到 slow.log。</p><p>看慢查询日志：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysqldumpslow</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> t</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/mysql/logs/slow.log</span></span></code></pre></div><p><code>mysqldumpslow</code> 把慢日志汇总统计——<code>-s t</code> 按总耗时排序，<code>-t 10</code> 取前 10 条。它会按查询模式合并（参数替换成 <code>S</code>、<code>N</code>），不会每条都列出来。</p><p>输出大致：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Count: 152  Time=3.21s (488s)  Lock=0.00s (0s)  Rows=1000.0 (152000)</span></span>
<span class="line"><span>  SELECT * FROM access_logs WHERE app_name=&#39;S&#39; AND status_code=N ORDER BY created_at DESC LIMIT N</span></span></code></pre></div><p><code>Count</code> 是这条模式执行了多少次，<code>Time</code> 是平均和总耗时。看到某条查询执行 152 次总耗时 488 秒，就是重点优化目标。</p><h2 id="五、定位到查询后的优化步骤" tabindex="-1">五、定位到查询后的优化步骤 <a class="header-anchor" href="#五、定位到查询后的优化步骤" aria-label="Permalink to &quot;五、定位到查询后的优化步骤&quot;">​</a></h2><ol><li><strong>EXPLAIN 看执行计划</strong>——type、key、rows、Extra 四个字段</li><li><strong>判断问题</strong>——没走索引？扫太多行？filesort？</li><li><strong>加或改索引</strong>——按最左前缀和列顺序原则</li><li><strong>改查询</strong>——避免函数包裹索引列、避免 SELECT *、避免前通配 LIKE</li><li><strong>验证</strong>——再 EXPLAIN 看 rows 降下来了、filesort 没了</li></ol><p>优化是个循环——改完看效果，还不满意再调。重点是拿 EXPLAIN 和慢日志的数据说话，不靠猜。</p><h2 id="执行计划之后" tabindex="-1">执行计划之后 <a class="header-anchor" href="#执行计划之后" aria-label="Permalink to &quot;执行计划之后&quot;">​</a></h2><p>查询优化讲完了。但 MySQL 存数据、查数据的底层——InnoDB 存储引擎——还没讲。为什么能回滚、为什么崩溃不丢数据、为什么有行锁，都和 InnoDB 有关。下一篇讲 InnoDB 存储引擎：Buffer Pool、Redo/Undo Log。</p>`,54)])])}const g=a(n,[["render",p]]);export{c as __pageData,g as default};
